import{_ as t,o as s,c as e,ah as a}from"./chunks/framework.zwOixAa1.js";const k=JSON.parse('{"title":"Upgrade Guide - v5","description":"Learn how to upgrade your Textwire code from v3 to v5","frontmatter":{"title":"Upgrade Guide - v5","description":"Learn how to upgrade your Textwire code from v3 to v5","outline":"deep"},"headers":[],"relativePath":"v5/upgrade.md","filePath":"versions/v5/upgrade.md","lastUpdated":1777824106000}'),n={name:"v5/upgrade.md"};function h(l,i,p,r,o,d){return s(),e("div",null,[...i[0]||(i[0]=[a('<h1 id="upgrade-guide" tabindex="-1">Upgrade Guide <a class="header-anchor" href="#upgrade-guide" aria-label="Permalink to &quot;Upgrade Guide&quot;">​</a></h1><p>Upgrading from v4 to v5 is the most easier upgrade yet. The only breaking change that was introduced is &quot;Raw string output&quot; syntax. Previously, in order to get unescaped string output you needed to use <a href="https://textwire.github.io/v4/functions/str#raw" target="_blank" rel="noreferrer">raw</a> function on strings like this:</p><div class="language-textwire vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">textwire</span><pre class="shiki shiki-themes github-light catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-style:inherit;--shiki-dark:#89B4FA;--shiki-dark-font-style:italic;">{{</span><span style="--shiki-light:#032F62;--shiki-dark:#A6E3A1;"> &quot;&lt;h1&gt;Test&lt;/h1&gt;&quot;</span><span style="--shiki-light:#D73A49;--shiki-dark:#CBA6F7;">.</span><span style="--shiki-light:#6F42C1;--shiki-light-font-style:inherit;--shiki-dark:#89B4FA;--shiki-dark-font-style:italic;">raw()</span><span style="--shiki-light:#005CC5;--shiki-light-font-style:inherit;--shiki-dark:#89B4FA;--shiki-dark-font-style:italic;"> }}</span></span></code></pre></div><p>In Textwire v5, <a href="https://textwire.github.io/v4/functions/str#raw" target="_blank" rel="noreferrer">raw</a> function was removed. In order to print raw output you now need to use this syntax:</p><div class="language-textwire vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">textwire</span><pre class="shiki shiki-themes github-light catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-style:inherit;--shiki-dark:#89B4FA;--shiki-dark-font-style:italic;">{!!</span><span style="--shiki-light:#032F62;--shiki-dark:#A6E3A1;"> &quot;&lt;h1&gt;Test&lt;/h1&gt;&quot;</span><span style="--shiki-light:#005CC5;--shiki-light-font-style:inherit;--shiki-dark:#89B4FA;--shiki-dark-font-style:italic;"> !!}</span></span></code></pre></div><p>We did it because <code>raw</code> function was causing a lot of issues where a string could be escaped multiple times causing the wrong output.</p><h2 id="steps" tabindex="-1">Steps <a class="header-anchor" href="#steps" aria-label="Permalink to &quot;Steps&quot;">​</a></h2><h3 id="_1-update-import-path" tabindex="-1">1. Update Import Path <a class="header-anchor" href="#_1-update-import-path" aria-label="Permalink to &quot;1. Update Import Path&quot;">​</a></h3><p>Replace all v4 imports with v5:</p><div class="language-go vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">go</span><pre class="shiki shiki-themes github-light catppuccin-mocha has-diff vp-code" tabindex="0"><code><span class="line diff remove"><span style="--shiki-light:#D73A49;--shiki-dark:#CBA6F7;">import</span><span style="--shiki-light:#032F62;--shiki-dark:#A6E3A1;"> &quot;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#A6E3A1;">github.com/textwire/textwire/v4</span><span style="--shiki-light:#032F62;--shiki-dark:#A6E3A1;">&quot;</span></span>\n<span class="line diff add"><span style="--shiki-light:#D73A49;--shiki-dark:#CBA6F7;">import</span><span style="--shiki-light:#032F62;--shiki-dark:#A6E3A1;"> &quot;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#A6E3A1;">github.com/textwire/textwire/v5</span><span style="--shiki-light:#032F62;--shiki-dark:#A6E3A1;">&quot;</span></span></code></pre></div><p>After updating imports, run:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-light-font-style:inherit;--shiki-dark:#89B4FA;--shiki-dark-font-style:italic;">go</span><span style="--shiki-light:#032F62;--shiki-dark:#A6E3A1;"> mod</span><span style="--shiki-light:#032F62;--shiki-dark:#A6E3A1;"> tidy</span></span></code></pre></div><h3 id="_2-replace-raw-function" tabindex="-1">2. Replace <code>raw</code> Function <a class="header-anchor" href="#_2-replace-raw-function" aria-label="Permalink to &quot;2. Replace `raw` Function&quot;">​</a></h3><p>If you use <code>raw</code> function in your code, replace it&#39;s usage with new syntax:</p><div class="language-textwire vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">textwire</span><pre class="shiki shiki-themes github-light catppuccin-mocha has-diff vp-code" tabindex="0"><code><span class="line diff remove"><span style="--shiki-light:#005CC5;--shiki-light-font-style:inherit;--shiki-dark:#89B4FA;--shiki-dark-font-style:italic;">{{</span><span style="--shiki-light:#24292E;--shiki-dark:#CBA6F7;"> post.description.</span><span style="--shiki-light:#6F42C1;--shiki-light-font-style:inherit;--shiki-dark:#89B4FA;--shiki-dark-font-style:italic;">raw()</span><span style="--shiki-light:#005CC5;--shiki-light-font-style:inherit;--shiki-dark:#89B4FA;--shiki-dark-font-style:italic;"> }}</span></span>\n<span class="line diff add"><span style="--shiki-light:#005CC5;--shiki-light-font-style:inherit;--shiki-dark:#89B4FA;--shiki-dark-font-style:italic;">{!!</span><span style="--shiki-light:#24292E;--shiki-dark:#CBA6F7;"> post.description</span><span style="--shiki-light:#005CC5;--shiki-light-font-style:inherit;--shiki-dark:#89B4FA;--shiki-dark-font-style:italic;"> !!}</span></span></code></pre></div>',15)])])}const u=t(n,[["render",h]]);export{k as __pageData,u as default};
